"use strict";parserFactory.register("manganelo.com",()=>new ManganeloParser);class ManganeloParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("div.panel-story-chapter-list a")].map(e=>util.hyperLinkToChapter(e)).reverse()}findContent(e){return e.querySelector("div.container-chapter-reader")}extractTitleImpl(e){return e.querySelector("div.story-info-right h1")}findChapterTitle(e){return e.querySelector("h1")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.story-info-left")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("#panel-story-info-description")]}}